// Tail call optimized
function factorialTail(n, acc = 1) {
  if (n <= 1) return acc;
  return factorialTail(n - 1, n * acc);
}

function factorialClassic(n) {
  return n <= 1 ? 1 : n * factorialClassic(n - 1);
}

function factorialBigInt(n) {
  if (n <= 1n) return 1n;
  return BigInt(n) * factorialBigInt(BigInt(n - 1));
}
